-- Movie Pairs Ranking
-- suggested_by: oriliss
--
-- I went through the movies I personally ranked and looked for pairs
-- that share something meaningful: same franchise, same director,
-- same lead actor, or similar genre and era.
--
-- For the bad recommendations I looked for pairs where the movies
-- seem similar on the surface but I rated one high and the other low.
-- Those are the most interesting false positives in my opinion.
--
-- Good pairs: 100  |  Bad/unreasonable pairs: 100  |  Total: 200

CREATE TABLE IF NOT EXISTS movies_recommendations (
    base_movie_id       INT          NOT NULL,
    recommended_movie_id INT         NOT NULL,
    recommendation      INT          NOT NULL,   -- 1 bad, 5 neutral, 10 great
    suggested_by        VARCHAR(100) NOT NULL,
    justification       TEXT,
    comment             TEXT
);

